const rawText = $input.item.json.candidates[0].content.parts[0].text || "";

function parseJSONBlock(rawString) {
  if (!rawString) return {};
  try {
    const firstBrace = rawString.indexOf('{');
    const lastBrace = rawString.lastIndexOf('}');
    if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
      const jsonCandidate = rawString.substring(firstBrace, lastBrace + 1);
      return JSON.parse(jsonCandidate);
    }
    return JSON.parse(rawString.replace(/```json/g, '').replace(/```/g, ''));
  } catch (e) {
    return { error: "JSON_PARSE_FAILED" };
  }
}

const mainObj = parseJSONBlock(rawText);

return {
  json: {
    config: mainObj.config || {},
    market_research: mainObj.market_research || {},
    persona: mainObj.persona || {},
    product_profile: mainObj.product_profile || {},
    creative_blueprint: mainObj.creative_blueprint || {},
    performance_forecast: mainObj.performance_forecast || {},
    strategy: mainObj.strategy || {}
  }
};

