const item = $input.item;

// 2. Check if binary data exists
if (item.binary) {
  // 3. Loop through every uploaded file (data, data_1, data_2)
  for (const key of Object.keys(item.binary)) {
    const binaryFile = item.binary[key];

    // 4. Create a separate item for each file
    // We keep the original JSON fields (Product Name, etc) on every item
    newItems.push({
      json: {
        ...item.json,
        originalBinaryKey: key // tracking ID
      },
      binary: {
        data: binaryFile // Standardize the binary key to just 'data' for the upload node
      }
    });
  }
}

return newItems;

// 1. Get the raw Master Prompt string
// We try multiple sources to be safe
const sourceJson = $('set_strategist_prompt').first().json;
const rawPromptString = sourceJson.text || sourceJson.prompt || sourceJson.promptText || sourceJson.sora_video_prompt;

// 2. Define the 'parts' array
const parts = [];

// 3. Add the Text Part
if (rawPromptString) {
  parts.push({
    "text": rawPromptString
  });
} else {
  parts.push({
    "text": "Error: Prompt text not found. Please check 'set_master_prompt' output."
  });
}

// 4. Get the Images (THE FIX)
// Instead of looking at the JSON 'filesystem-v2' pointer, we look for the actual Binary attachments on the input items.

// Check if the input items have binary data
if (items[0].binary) {
  const binaryKeys = Object.keys(items[0].binary);

  for (const key of binaryKeys) {
    const binaryObj = items[0].binary[key];

    // Safety check: ensure it is actually an image
    if (binaryObj.mimeType && binaryObj.mimeType.startsWith('image/')) {

      // CRITICAL STEP: Read the file from disk to memory
      const buffer = await this.helpers.getBinaryDataBuffer(0, key);

      parts.push({
        inline_data: {
          mime_type: binaryObj.mimeType,
          data: buffer.toString('base64') // Convert to the Base64 string Gemini needs
        }
      });
    }
  }
}

// 5. Fallback (If no binaries found on input)
// If parts only has text, we log a warning.
if (parts.length === 1) {
    console.log("WARNING: No binary images found in input. Check if 'set_master_prompt' is stripping binaries.");
}

// 6. Return the FULL API BODY structure
return {
  json: {
    contents: [
      {
        parts: parts
      }
    ]
  }
};

