// This node acts as a "Collector." 
// It passes through whichever branch actually contains the data.
const allInputs = $input.all();

// Filter for the item that has a valid Preset value.
// We ignore the "Empty" branch that didn't run.
const validOutput = allInputs.filter(item => {
  const p = item.json.Preset;
  return p !== undefined && p !== null && p !== "" && p !== "null";
});

// Return the valid data so the Switch node only sees the "Full" item.
return validOutput.length > 0 ? validOutput : [];
